+
+impl WalChecksumTransform {
+    /// Identity transform.
+    #[must_use]
+    pub const fn identity() -> Self {
+        Self {
+            a11: 1,
+            a12: 0,
+            a21: 0,
+            a22: 1,
+            c1: 0,
+            c2: 0,
+        }
+    }
+
+    #[must_use]
+    fn from_checksum_words(x0: u32, x1: u32) -> Self {
+        Self {
+            a11: 1,
+            a12: 1,
+            a21: 1,
+            a22: 2,
+            c1: x0,
+            c2: x0.wrapping_add(x1),
+        }
+    }
+
+    /// Apply this transform to a running checksum seed.
